double myPow(double x, int n) {
    long N = n;
    if (N < 0) { x = 1.0 / x; N = -N; }
    double res = 1.0;
    while (N) {
        if (N & 1) res *= x;
        x *= x; N >>= 1;
    }
    return res;
}
